// This file is generated by AI.

use std::{hint::black_box, time::Duration};

use criterion::{Criterion, Throughput, criterion_group, criterion_main};
use rand::{RngExt, SeedableRng, rngs::StdRng};
use webgal_model::sentence::{FromPrimary, PrimarySentence, Sentence};

// -------- data --------

const SCENE: &str = include_str!("fixtures/sample.txt");

fn load_lines() -> Vec<&'static str> {
    SCENE.lines().collect()
}

/// 从原始行中随机抽取 n 条语句 (有放回)
fn sample_lines(lines: &[&'static str], n: usize, rng: &mut impl RngExt) -> Vec<&'static str> {
    (0..n)
        .map(|_| lines[rng.random_range(0..lines.len())])
        .collect()
}

// -------- bench groups --------

/// 只测 PrimarySentence 解析 (词法解析, 不校验内容)
fn bench_primary_parse(c: &mut Criterion) {
    let all_lines = load_lines();
    let total_lines = all_lines.len();
    eprintln!("Total lines in scene: {}", total_lines);

    let size = 1000;
    let mut rng = StdRng::seed_from_u64(42);
    let sampled = sample_lines(&all_lines, size, &mut rng);

    let mut group = c.benchmark_group("primary_parse");
    group.sample_size(40);
    group.warm_up_time(Duration::from_millis(500));
    group.measurement_time(Duration::from_secs(4));
    group.throughput(Throughput::Elements(size as u64));
    group.bench_function("PrimarySentence::from_str", |b| {
        b.iter(|| {
            for line in &sampled {
                let primary = PrimarySentence::from_str(black_box(line));
                black_box(primary);
            }
        })
    });
    group.finish();
}

/// 测 Sentence::from_str 直接解析 (含类型转换, 忽略错误)
fn bench_sentence_from_str(c: &mut Criterion) {
    let all_lines = load_lines();
    let size = 1000;
    let mut rng = StdRng::seed_from_u64(42);
    let sampled = sample_lines(&all_lines, size, &mut rng);

    let mut group = c.benchmark_group("sentence_from_str");
    group.sample_size(40);
    group.warm_up_time(Duration::from_millis(500));
    group.measurement_time(Duration::from_secs(4));
    group.throughput(Throughput::Elements(size as u64));
    group.bench_function("Sentence::from_str", |b| {
        b.iter(|| {
            for line in &sampled {
                let output = Sentence::from_str(black_box(line));
                black_box(output);
            }
        })
    });
    group.finish();
}

/// 测从 PrimarySentence 构建 Sentence (已忽略错误, 只测构建过程)
fn bench_sentence_from_primary(c: &mut Criterion) {
    let all_lines = load_lines();
    let size = 1000;
    let mut rng = StdRng::seed_from_u64(42);
    let sampled = sample_lines(&all_lines, size, &mut rng);

    // 预先解析出 PrimarySentence
    let primaries: Vec<PrimarySentence> = sampled
        .iter()
        .map(|line| PrimarySentence::from_str(line))
        .collect();

    let mut group = c.benchmark_group("sentence_from_primary");
    group.sample_size(40);
    group.warm_up_time(Duration::from_millis(500));
    group.measurement_time(Duration::from_secs(4));
    group.throughput(Throughput::Elements(size as u64));
    group.bench_function("FromPrimary::from_primary", |b| {
        b.iter(|| {
            for primary in &primaries {
                let mut errors = Vec::new();
                let sentence = Sentence::from_primary(black_box(primary), &mut errors);
                black_box((sentence, errors));
            }
        })
    });
    group.finish();
}

/// 测 Sentence 序列化 (Display)
fn bench_sentence_display(c: &mut Criterion) {
    let all_lines = load_lines();
    let size = 1000;
    let mut rng = StdRng::seed_from_u64(42);
    let sampled = sample_lines(&all_lines, size, &mut rng);

    // 预先解析出 Sentence, 忽略错误
    let sentences: Vec<Sentence> = sampled
        .iter()
        .filter_map(|line| {
            let output = Sentence::from_str(line);
            if output.has_error() {
                Some(output.sentence)
            } else {
                None
            }
        })
        .collect();
    let actual_count = sentences.len();
    eprintln!("Successfully parsed {} out of {} lines", actual_count, size);

    let mut group = c.benchmark_group("sentence_display");
    group.sample_size(40);
    group.warm_up_time(Duration::from_millis(500));
    group.measurement_time(Duration::from_secs(4));
    group.throughput(Throughput::Elements(actual_count as u64));
    group.bench_function("Display::fmt", |b| {
        b.iter(|| {
            for s in &sentences {
                let formatted = s.to_string();
                black_box(formatted);
            }
        })
    });
    group.finish();
}

criterion_group!(
    benches,
    bench_primary_parse,
    bench_sentence_from_str,
    bench_sentence_from_primary,
    bench_sentence_display
);
criterion_main!(benches);
